CREATE TABLE customers (id BIGINT AUTO_INCREMENT PRIMARY KEY, persona VARCHAR(30) NOT NULL UNIQUE, email VARCHAR(120) NOT NULL UNIQUE, password_hash VARCHAR(255) NOT NULL DEFAULT 'ENV_REQUIRED', display_name VARCHAR(100) NOT NULL);
CREATE TABLE products (sku VARCHAR(30) PRIMARY KEY, name VARCHAR(120) NOT NULL, price_paise INT UNSIGNED NOT NULL, stock INT UNSIGNED NOT NULL);
CREATE TABLE carts (id BIGINT AUTO_INCREMENT PRIMARY KEY, customer_id BIGINT NOT NULL, status ENUM('OPEN','ORDERED') NOT NULL DEFAULT 'OPEN', CONSTRAINT fk_carts_customer FOREIGN KEY (customer_id) REFERENCES customers(id));
CREATE TABLE cart_items (cart_id BIGINT NOT NULL, sku VARCHAR(30) NOT NULL, qty INT UNSIGNED NOT NULL, unit_price_paise INT UNSIGNED NOT NULL, PRIMARY KEY (cart_id, sku), CONSTRAINT fk_cart_item_cart FOREIGN KEY (cart_id) REFERENCES carts(id), CONSTRAINT fk_cart_item_product FOREIGN KEY (sku) REFERENCES products(sku));
CREATE TABLE orders (id BIGINT AUTO_INCREMENT PRIMARY KEY, customer_id BIGINT NOT NULL, cart_id BIGINT NOT NULL UNIQUE, status ENUM('PLACED','CANCELLED') NOT NULL DEFAULT 'PLACED', total_paise INT UNSIGNED NOT NULL, address VARCHAR(240) NOT NULL, CONSTRAINT fk_order_customer FOREIGN KEY (customer_id) REFERENCES customers(id), CONSTRAINT fk_order_cart FOREIGN KEY (cart_id) REFERENCES carts(id));
